403: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
404:   state_ = State::Complete;
405:   using Filters::Common::ExtAuthz::CheckStatus;
406:   Stats::StatName empty_stat_name;
407: 
408:   if (!response->dynamic_metadata.fields().empty()) {
409:     if (!config_->enableDynamicMetadataIngestion()) {
