52: // SuccessResponse used for creating either DENIED or OK authorization responses.
53: struct SuccessResponse {
54:   SuccessResponse(const Http::HeaderMap& headers, const MatcherSharedPtr& matchers,
55:                   const MatcherSharedPtr& append_matchers,
56:                   const MatcherSharedPtr& response_matchers,
57:                   const MatcherSharedPtr& dynamic_metadata_matchers, Response&& response)
58:       : headers_(headers), matchers_(matchers), append_matchers_(append_matchers),
59:         response_matchers_(response_matchers),
60:         to_dynamic_metadata_matchers_(dynamic_metadata_matchers),
61:         response_(std::make_unique<Response>(response)) {
62:     headers_.iterate([this](const Http::HeaderEntry& header) -> Http::HeaderMap::Iterate {
63:       // UpstreamHeaderMatcher
64:       if (matchers_->matches(header.key().getStringView())) {
65:         response_->headers_to_set.emplace_back(header.key().getStringView(),
66:                                                header.value().getStringView());
67:       }
68:       if (append_matchers_->matches(header.key().getStringView())) {
69:         // If there is an existing matching key in the current headers, the new entry will be
70:         // appended with the same key. For example, given {"key": "value1"} headers, if there is
71:         // a matching "key" from the authorization response headers {"key": "value2"}, the
72:         // request to upstream server will have two entries for "key": {"key": "value1", "key":
73:         // "value2"}.
74:         response_->headers_to_add.emplace_back(header.key().getStringView(),
75:                                                header.value().getStringView());
76:       }
77:       if (response_matchers_->matches(header.key().getStringView())) {
78:         // For HTTP implementation, the response headers from the auth server will, by default, be
79:         // appended (using addCopy) to the encoded response headers.
80:         response_->response_headers_to_add.emplace_back(header.key().getStringView(),
81:                                                         header.value().getStringView());
82:       }
83:       if (to_dynamic_metadata_matchers_->matches(header.key().getStringView())) {
84:         const std::string key{header.key().getStringView()};
85:         const std::string value{header.value().getStringView()};
86:         (*response_->dynamic_metadata.mutable_fields())[key] = ValueUtil::stringValue(value);
87:       }
88:       return Http::HeaderMap::Iterate::Continue;
89:     });
90:   }
91: 
92:   const Http::HeaderMap& headers_;
93:   // All matchers below are used on headers_.
94:   const MatcherSharedPtr& matchers_;
95:   const MatcherSharedPtr& append_matchers_;
96:   const MatcherSharedPtr& response_matchers_;
97:   const MatcherSharedPtr& to_dynamic_metadata_matchers_;
98:   ResponsePtr response_;
99: };
