152: MatcherSharedPtr
153: ClientConfig::toClientMatchers(const envoy::type::matcher::v3::ListStringMatcher& list,
154:                                Server::Configuration::CommonFactoryContext& context) {
155:   std::vector<Matchers::StringMatcherPtr> matchers(
156:       CheckRequestUtils::createStringMatchers(list, context));
157: 
158:   // If list is empty, all authorization response headers, except Host, should be added to
159:   // the client response.
160:   if (matchers.empty()) {
161:     envoy::type::matcher::v3::StringMatcher matcher;
162:     matcher.set_exact(Http::Headers::get().Host.get());
163:     matchers.push_back(
164:         std::make_unique<Matchers::StringMatcherImpl<envoy::type::matcher::v3::StringMatcher>>(
165:             matcher, context));
166: 
167:     return std::make_shared<NotHeaderKeyMatcher>(std::move(matchers));
168:   }
169: 
170:   // If not empty, all user defined matchers and default matcher's list will
171:   // be used instead.
172:   std::vector<Http::LowerCaseString> keys{
173:       {Http::Headers::get().Status, Http::Headers::get().ContentLength,
174:        Http::Headers::get().WWWAuthenticate, Http::Headers::get().Location}};
175: 
176:   for (const auto& key : keys) {
177:     envoy::type::matcher::v3::StringMatcher matcher;
178:     matcher.set_exact(key.get());
179:     matchers.push_back(
180:         std::make_unique<Matchers::StringMatcherImpl<envoy::type::matcher::v3::StringMatcher>>(
181:             matcher, context));
182:   }
183: 
184:   return std::make_shared<HeaderKeyMatcher>(std::move(matchers));
185: }
