291: void RawHttpClientImpl::onSuccess(const Http::AsyncClient::Request&,
292:                                   Http::ResponseMessagePtr&& message) {
293:   callbacks_->onComplete(toResponse(std::move(message)));
294:   callbacks_ = nullptr;
